void EntryOrder(ENUM_ORDER_TYPE orderType,double lot,double price, int stopLossPips,int takeProfitPips)
  {
   CTrade trade;
   double sl = 0;
   double tp = 0;
   if(orderType == OP_BUY)
     {
      if(stopLossPips > 0) sl = price - stopLossPips * _Point;
      if(takeProfitPips > 0) tp = price + takeProfitPips * _Point;
      trade.Buy(lot,price,sl,tp);
     }
   else if (orderType == OP_SELL)
     {
      if(stopLossPips > 0) sl = price + stopLossPips * _Point;
      if(takeProfitPips > 0) tp = price - takeProfitPips * _Point;
      trade.Sell(lot,price,sl,tp);
     }
  }

