void CloseAllSellOrders()
  {
   for(int i=OrdersTotal()-1; i>=0; i--)
     {
      if(!OrderSelect(i,SELECT_BY_POS,MODE_TRADES))
         continue;
      if(OrderSymbol()!=Symbol() || OrderMagicNumber()!=0 || OrderType()!=OP_SELL)
         continue;
      CTrade trade;
      trade.OrderClose(OrderTicket(),OrderLots(),Bid);
     }
  }

